3040	
3041	pub static RBTDRC_CASES_HALLMARK_LIFECYCLE: &[rbtdre_Case] = &[case!(rbtdrc_hallmark_lifecycle)];
3042	
3043	
3044	// Lode-lifecycle fixture — fetched-side base capture against live GAR. Single
3045	// self-contained round-trip: ensconce the busybox base into a fresh rbi_ld
3046	// Lode, divine-enumerate to confirm it appears, divine-inspect to confirm the
3047	// member tags + vouch envelope rode in, banish the whole Lode, then divine-
3048	// enumerate to confirm the registry is restored. Parallel to hallmark-lifecycle
3049	// on the made side. Requires a reliquary yoked on the busybox vessel (same
3050	// precondition hallmark-lifecycle's ordain carries).
3051	fn rbtdrc_lode_lifecycle(dir: &Path) -> rbtdre_Verdict {
3052	    rbtdrc_with_ctx(|ctx| {
3053	        let vessel_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
3054	        if !ctx.project_root().join(vessel_dir).is_dir() {
3055	            return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vessel_dir));
3056	        }
3057	
3058	        // Step 1: ensconce the busybox base into a fresh Lode.
3059	        let _ = std::fs::write(dir.join("01-ensconce.txt"), "ensconcing busybox base");
3060	        let ensconce = match rbtdri_invoke_global(ctx, RBTDGC_ENSCONCE_BOLE, &[vessel_dir], &[]) {
3061	            Ok(r) if r.exit_code == 0 => r,
3062	            Ok(r) => return rbtdre_Verdict::Fail(format!("ensconce failed (exit {})\n{}", r.exit_code, r.stderr)),
3063	            Err(e) => return rbtdre_Verdict::Fail(format!("ensconce invocation: {}", e)),
3064	        };
3065	        let _ = std::fs::write(dir.join("01-ensconce-stdout.txt"), &ensconce.stdout);
3066	
3067	        // The host-side capture handoff is the bare touchmark fact.
3068	        let touchmark = match rbtdri_read_burv_fact(&ensconce, RBTDRC_FACT_LODE_TOUCHMARK) {
3069	            Ok(v) => v,
3070	            Err(e) => return rbtdre_Verdict::Fail(format!("read touchmark fact: {}", e)),
3071	        };
3072	        let _ = std::fs::write(dir.join("02-touchmark.txt"), &touchmark);
3073	
3074	        // Step 2: divine enumerate shows the new Lode.
3075	        let after = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[], &[]) {
3076	            Ok(r) if r.exit_code == 0 => r,
3077	            Ok(r) => return rbtdre_Verdict::Fail(format!("post-ensconce divine failed (exit {})\n{}", r.exit_code, r.stderr)),
3078	            Err(e) => return rbtdre_Verdict::Fail(format!("post-ensconce divine invocation: {}", e)),
3079	        };
3080	        let _ = std::fs::write(dir.join("03-divine-after.txt"), &after.stdout);
3081	        if !after.stdout.contains(&touchmark) {
3082	            return rbtdre_Verdict::Fail(format!(
3083	                "post-ensconce divine missing touchmark {}\nstdout:\n{}",
3084	                touchmark, after.stdout
3085	            ));
3086	        }
3087	
3088	        // Step 3: divine inspect shows the member tags + the vouch envelope.
3089	        let inspect = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[&touchmark], &[]) {
3090	            Ok(r) if r.exit_code == 0 => r,
3091	            Ok(r) => return rbtdre_Verdict::Fail(format!("divine inspect failed (exit {})\n{}", r.exit_code, r.stderr)),
3092	            Err(e) => return rbtdre_Verdict::Fail(format!("divine inspect invocation: {}", e)),
3093	        };
3094	        let _ = std::fs::write(dir.join("04-divine-inspect.txt"), &inspect.stdout);
3095	        for member in &[RBTDRC_LODE_TAG_BOLE, RBTDRC_LODE_TAG_VOUCH, RBTDRC_LODE_TAG_DIGEST_PREFIX] {
3096	            if !inspect.stdout.contains(member) {
3097	                return rbtdre_Verdict::Fail(format!(
3098	                    "divine inspect missing member tag '{}'\nstdout:\n{}",
3099	                    member, inspect.stdout
3100	                ));
3101	            }
3102	        }
3103	
3104	        // Step 4: banish the whole Lode.
3105	        let _ = std::fs::write(dir.join("05-banish.txt"), "banishing");
3106	        match rbtdri_invoke_global(
3107	            ctx,
3108	            RBTDGC_BANISH_LODE,
3109	            &[&touchmark],
3110	            &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)],
3111	        ) {
3112	            Ok(r) if r.exit_code == 0 => {}
3113	            Ok(r) => return rbtdre_Verdict::Fail(format!("banish failed (exit {})\n{}", r.exit_code, r.stderr)),
3114	            Err(e) => return rbtdre_Verdict::Fail(format!("banish invocation: {}", e)),
3115	        }
3116	
3117	        // Step 5: divine enumerate no longer shows the Lode — registry restored.
3118	        let final_divine = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[], &[]) {
3119	            Ok(r) if r.exit_code == 0 => r,
3120	            Ok(r) => return rbtdre_Verdict::Fail(format!("final divine failed (exit {})\n{}", r.exit_code, r.stderr)),
3121	            Err(e) => return rbtdre_Verdict::Fail(format!("final divine invocation: {}", e)),
3122	        };
3123	        let _ = std::fs::write(dir.join("06-divine-final.txt"), &final_divine.stdout);
3124	        if final_divine.stdout.contains(&touchmark) {
3125	            return rbtdre_Verdict::Fail(format!(
3126	                "final divine still shows banished touchmark {} — banish did not restore baseline\nstdout:\n{}",
3127	                touchmark, final_divine.stdout
3128	            ));
3129	        }
3130	
3131	        let _ = std::fs::write(dir.join("07-passed.txt"), "passed");
3132	        rbtdre_Verdict::Pass
3133	    })
3134	}
3135	
3136	// Lode-collision case — exercises the cloud-side touchmark collision guard
3137	// (rbgjl01-ensconce-capture.sh). The guard cannot fire under natural minting:
3138	// each ensconce mints a fresh second-grained stamp, so two CLI captures land on
3139	// distinct touchmarks. We pin the stamp via the buo tweak channel
3140	// (RBTDRC_ENSCONCE_STAMP_TWEAK_NAME) to drive both captures onto ONE touchmark.
3141	//
3142	// Sequence: (1) ensconce busybox naturally -> mint touchmark S, read it back;
3143	// (2) ensconce busybox pinned to S -> identical digest, guard's idempotent
3144	// branch, exit 0; (3) ensconce debian pinned to S -> different digest under the
3145	// same touchmark, guard's collision branch, host exit non-zero; (4) banish S.
3146	//
3147	// The collision verdict rests on the HOST EXIT CODE: the guard's "touchmark
3148	// collision" message lands in Cloud Logging (CLOUD_LOGGING_ONLY), not host
3149	// stdout, but a cloud build FAILURE propagates to a non-zero rbw-lE exit
3150	// (rbfcb_BuildHost.sh: status != SUCCESS -> buc_die). The idempotent step (2) is
3151	// the positive control: the identical pipeline on the same pinned touchmark
3152	// SUCCEEDS for the same base, so step (3)'s failure isolates to the differing
3153	// digest — the collision branch — not debian-specific infra. Both vessels carry
3154	// the same yoked reliquary, so host-side skopeo resolution is identical.
3155	fn rbtdrc_lode_collision(dir: &Path) -> rbtdre_Verdict {
3156	    rbtdrc_with_ctx(|ctx| {
3157	        let busybox_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
3158	        let deb_dir = RBTDRC_DEB_VESSEL_DIR;
3159	        for vd in &[busybox_dir, deb_dir] {
3160	            if !ctx.project_root().join(vd).is_dir() {
3161	                return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vd));
3162	            }
3163	        }
3164	
3165	        // Step 1: ensconce busybox naturally; read back the minted touchmark S.
3166	        let _ = std::fs::write(dir.join("01-ensconce-fresh.txt"), "ensconcing busybox (fresh, natural mint)");
3167	        let fresh = match rbtdri_invoke_global(ctx, RBTDGC_ENSCONCE_BOLE, &[busybox_dir], &[]) {
3168	            Ok(r) if r.exit_code == 0 => r,
3169	            Ok(r) => return rbtdre_Verdict::Fail(format!("fresh ensconce failed (exit {})\n{}", r.exit_code, r.stderr)),
3170	            Err(e) => return rbtdre_Verdict::Fail(format!("fresh ensconce invocation: {}", e)),
3171	        };
3172	        let _ = std::fs::write(dir.join("01-ensconce-fresh-stdout.txt"), &fresh.stdout);
3173	        let touchmark = match rbtdri_read_burv_fact(&fresh, RBTDRC_FACT_LODE_TOUCHMARK) {
3174	            Ok(v) => v,
3175	            Err(e) => return rbtdre_Verdict::Fail(format!("read touchmark fact: {}", e)),
3176	        };
3177	        let _ = std::fs::write(dir.join("02-touchmark.txt"), &touchmark);
3178	
3179	        let pin = &[
3180	            ("BURE_TWEAK_NAME", RBTDRC_ENSCONCE_STAMP_TWEAK_NAME),
3181	            ("BURE_TWEAK_VALUE", touchmark.as_str()),
3182	        ];
3183	
3184	        // Step 2 (positive control): ensconce busybox pinned to S — identical
3185	        // digest under the same touchmark — guard's idempotent branch — must PASS.
3186	        let _ = std::fs::write(dir.join("03-ensconce-idempotent.txt"), "ensconcing busybox pinned to S (identical digest)");
3187	        let idem = match rbtdri_invoke_global(ctx, RBTDGC_ENSCONCE_BOLE, &[busybox_dir], pin) {
3188	            Ok(r) if r.exit_code == 0 => r,
3189	            Ok(r) => return rbtdre_Verdict::Fail(format!(
3190	                "idempotent ensconce (same base, same touchmark) should pass but failed (exit {})\n{}",
3191	                r.exit_code, r.stderr)),
3192	            Err(e) => return rbtdre_Verdict::Fail(format!("idempotent ensconce invocation: {}", e)),
3193	        };
3194	        let _ = std::fs::write(dir.join("03-ensconce-idempotent-stdout.txt"), &idem.stdout);
3195	
3196	        // Step 3: ensconce debian pinned to S — different digest under the same
3197	        // touchmark — guard's collision branch — host exit must be non-zero.
3198	        let _ = std::fs::write(dir.join("04-ensconce-collision.txt"), "ensconcing debian pinned to S (different digest -> collision)");
3199	        let collision = match rbtdri_invoke_global(ctx, RBTDGC_ENSCONCE_BOLE, &[deb_dir], pin) {
3200	            Ok(r) => r,
3201	            Err(e) => return rbtdre_Verdict::Fail(format!("collision ensconce invocation: {}", e)),
3202	        };
3203	        let _ = std::fs::write(dir.join("04-ensconce-collision-stdout.txt"), &collision.stdout);
3204	        let _ = std::fs::write(dir.join("04-ensconce-collision-stderr.txt"), &collision.stderr);
3205	        if collision.exit_code == 0 {
3206	            return rbtdre_Verdict::Fail(format!(
3207	                "collision ensconce (different base, same touchmark {}) should fail loud but exited 0\nstdout:\n{}",
3208	                touchmark, collision.stdout));
3209	        }
3210	
3211	        // Step 4: banish S — cleanup (removes the busybox Lode steps 1-2 left;
3212	        // the collision step wrote nothing, dying before the GAR copy).
3213	        let _ = std::fs::write(dir.join("05-banish.txt"), "banishing");
3214	        match rbtdri_invoke_global(
3215	            ctx,
