buc_doc_brief() {
  set -e
  ZBUC_USAGE_STRING="${ZBUC_CONTEXT}"
  zbuc_doc_mode_predicate || return 0
  echo
  zbuc_tint BUYC_BRIGHT_WHITE "${ZBUC_CONTEXT}"
  echo "  ${z_buym_format}"
  echo "    brief: $1"
}

buc_doc_lines() {
  set -e
  zbuc_doc_mode_predicate || return 0
  echo "           $1"
}

buc_doc_param() {
  set -e
  ZBUC_USAGE_STRING="${ZBUC_USAGE_STRING} <<$1>>"
  zbuc_doc_mode_predicate || return 0
  echo "    required: $1 - $2"
}

buc_doc_oparm() {
  set -e
  ZBUC_USAGE_STRING="${ZBUC_USAGE_STRING} [<<$1>>]"
  zbuc_doc_mode_predicate || return 0
  echo "    optional: $1 - $2"
}

